#!/usr/bin/env node
// @ai-generated — Claude Sonnet 4.6 (Anthropic)
/**
 * SAST/DAST Scan Evidence Extractor
 *
 * Reads audits/sast-dast-scan.md and audits/cwe-mapping.md generated by
 * the post-commit-audit tool, parses findings and CWE mappings, then
 * validates coverage against known security test suites.
 *
 * Zero external dependencies — uses only Node.js built-ins (fs, path).
 * No child_process usage — this extractor reads files only.
 *
 * Usage:
 *   node sast-dast-evidence.js [--repo <path>] [--output <path>]
 *
 * Serves as evidence for:
 *   T15  Security Assessment
 *   T24  SAST/DAST Scan Validation
 */

const fs = require('fs');
const path = require('path');

// ---------------------------------------------------------------------------
// CLI argument parsing
// ---------------------------------------------------------------------------

function parseArgs(argv) {
  var args = { repo: process.cwd(), output: null };
  for (var i = 2; i < argv.length; i++) {
    if (argv[i] === '--repo' && argv[i + 1]) {
      args.repo = path.resolve(argv[++i]);
    } else if (argv[i] === '--output' && argv[i + 1]) {
      args.output = path.resolve(argv[++i]);
    } else if (argv[i] === '--help' || argv[i] === '-h') {
      process.stderr.write(
        'Usage: node sast-dast-evidence.js [--repo <path>] [--output <path>]\n' +
        '  --repo    Path to git repository (default: current directory)\n' +
        '  --output  Write JSON to file instead of stdout\n'
      );
      process.exit(0);
    }
  }
  return args;
}

// ---------------------------------------------------------------------------
// Utility helpers
// ---------------------------------------------------------------------------

function log(msg) {
  process.stderr.write('[sast-dast-evidence] ' + msg + '\n');
}

function readText(p) {
  try { return fs.readFileSync(p, 'utf8'); } catch (e) { return null; }
}

function existsSync(p) {
  try { fs.statSync(p); return true; } catch (e) { return false; }
}

function isDir(p) {
  try { return fs.statSync(p).isDirectory(); } catch (e) { return false; }
}

