// ---------------------------------------------------------------------------
// Markdown table parser
// ---------------------------------------------------------------------------

/**
 * Parse a markdown table into an array of row objects.
 * Expects: | Header1 | Header2 | ... |
 *          |---------|---------|-----|
 *          | val1    | val2    | ... |
 */
function parseMarkdownTable(text, headerPattern) {
  var lines = text.split('\n');
  var tableStart = -1;

  for (var i = 0; i < lines.length; i++) {
    if (lines[i].indexOf('|') !== -1 && headerPattern.test(lines[i])) {
      tableStart = i;
      break;
    }
  }
  if (tableStart === -1) return [];

  var headerLine = lines[tableStart];
  var headers = headerLine.split('|')
    .map(function(h) { return h.trim(); })
    .filter(function(h) { return h.length > 0; });

  var dataStart = tableStart + 2;
  var rows = [];

  for (var j = dataStart; j < lines.length; j++) {
    var line = lines[j].trim();
    if (!line || line.indexOf('|') === -1) break;
    if (/^\|[\s-|]+\|$/.test(line)) continue;

    var cells;
    if (line.charAt(0) === '|') {
      cells = line.slice(1).split('|').map(function(c) { return c.trim(); });
      if (cells[cells.length - 1] === '') cells.pop();
    } else {
      cells = line.split('|').map(function(c) { return c.trim(); });
    }

    var row = {};
    for (var k = 0; k < headers.length && k < cells.length; k++) {
      row[headers[k]] = cells[k];
    }
    rows.push(row);
  }

  return rows;
}

// ---------------------------------------------------------------------------
// SAST/DAST scan parser
// ---------------------------------------------------------------------------

function parseSastDastScan(content) {
  var result = {
    detected: true,
    scanDate: null,
    scanner: null,
    filesScanned: 0,
    overallAssessment: null,
    findings: {
      critical: 0, high: 0, medium: 0, low: 0, info: 0, total: 0
    },
    individualFindings: [],
    dastFindings: null
  };

  var dateMatch = content.match(/\*\*Scan Date:\*\*\s*(.+)/);
  if (dateMatch) result.scanDate = dateMatch[1].trim();

  var scannerMatch = content.match(/\*\*Scanner:\*\*\s*(.+)/);
  if (scannerMatch) result.scanner = scannerMatch[1].trim();

  var filesMatch = content.match(/\*\*Files Scanned:\*\*\s*(\d+)/);
  if (filesMatch) result.filesScanned = parseInt(filesMatch[1], 10);

  var assessmentMatch = content.match(/## Overall Assessment\s*\n+\*\*(\w+)\*\*/);
  if (assessmentMatch) result.overallAssessment = assessmentMatch[1];

  // Parse severity summary table
  var summaryRows = parseMarkdownTable(content, /Severity/i);
  for (var i = 0; i < summaryRows.length; i++) {
    var row = summaryRows[i];
    var severity = (row['Severity'] || '').replace(/\*+/g, '').trim().toLowerCase();
    var countStr = row['This Audit'] || row['Count'] || '0';
    var count = parseInt(countStr, 10) || 0;

    if (severity === 'critical') result.findings.critical = count;
    else if (severity === 'high') result.findings.high = count;
    else if (severity === 'medium') result.findings.medium = count;
    else if (severity === 'low') result.findings.low = count;
    else if (severity === 'info') result.findings.info = count;
    else if (severity === 'total') result.findings.total = count;
  }

  if (result.findings.total === 0) {
    result.findings.total = result.findings.critical + result.findings.high +
      result.findings.medium + result.findings.low + result.findings.info;
  }

  // Extract individual findings from ### headings with CWE references
  var findingPattern = /###\s+(RESOLVED|MEDIUM|HIGH|CRITICAL|LOW|INFO|OPEN|MITIGATED)\s*[-\u2014]\s*(.+)/gi;
  var match;
  while ((match = findingPattern.exec(content)) !== null) {
    var status = match[1].toUpperCase();
    var title = match[2].trim();

    var sectionEnd = content.indexOf('\n###', match.index + 1);
    if (sectionEnd === -1) sectionEnd = content.indexOf('\n## ', match.index + 1);
    if (sectionEnd === -1) sectionEnd = content.length;
    var section = content.substring(match.index, sectionEnd);

    var cweMatch = section.match(/CWE-(\d+)/);
    var cweId = cweMatch ? 'CWE-' + cweMatch[1] : null;

    if (status === 'RESOLVED') status = 'RESOLVED';
    else if (status === 'MITIGATED') status = 'MITIGATED';
    else status = 'OPEN';

    result.individualFindings.push({
      title: title.replace(/\(was .+?\)/, '').replace(/\(.+?\)/, '').trim(),
      status: status,
      cwe: cweId,
      originalSeverity: match[1].toUpperCase()
    });
  }

  // DAST section
  var dastSection = content.match(/## DAST Findings\s*\n+([\s\S]*?)(?=\n## |\n---|\n$)/);
  if (dastSection) {
    var dastText = dastSection[1].trim();
    if (/N\/A|no web-facing/i.test(dastText)) {
      result.dastFindings = 'N/A - no web-facing components';
    } else {
      result.dastFindings = dastText;
    }
  }

  return result;
}

// ---------------------------------------------------------------------------
// CWE mapping parser
// ---------------------------------------------------------------------------

function parseCweMapping(content) {
  var result = {
    detected: true,
    uniqueCwes: 0,
    activeCwes: 0,
    resolvedCwes: 0,
    cweInventory: [],
    frameworkCoverage: {},
    aggregateMatrix: {}
  };

  var uniqueMatch = content.match(/\*\*Unique CWEs:\*\*\s*(\d+)/);
  if (uniqueMatch) result.uniqueCwes = parseInt(uniqueMatch[1], 10);

  // Parse CWE inventory table
  var inventoryRows = parseMarkdownTable(content, /CWE ID/i);
  for (var i = 0; i < inventoryRows.length; i++) {
    var row = inventoryRows[i];
    var cweId = (row['CWE ID'] || '').trim();
    var name = (row['Name'] || '').trim();
    var severity = (row['Original Severity'] || '').trim();
    var status = (row['Current Status'] || '').trim();

    if (!cweId) continue;

    var isResolved = /RESOLVED/i.test(status);
    var isMitigated = /MITIGATED/i.test(status);

    if (isResolved) result.resolvedCwes++;
    if (!isResolved && !isMitigated) result.activeCwes++;

    result.cweInventory.push({
      id: cweId,
      name: name,
      severity: severity,
      status: isResolved ? 'RESOLVED' : (isMitigated ? 'MITIGATED' : 'OPEN'),
      rawStatus: status
    });
  }

  // Parse compliance framework cross-reference table
  var frameworkRows = parseMarkdownTable(content, /CWE.*OWASP/i);
  var frameworkHeaders = [];
  if (frameworkRows.length > 0) {
    frameworkHeaders = Object.keys(frameworkRows[0]).filter(function(k) {
      return k !== 'CWE' && k !== 'Status';
    });
  }

  for (var f = 0; f < frameworkHeaders.length; f++) {
    var framework = frameworkHeaders[f];
    var mapped = [];
    var active = [];
    for (var j = 0; j < frameworkRows.length; j++) {
      var cellValue = (frameworkRows[j][framework] || '').trim();
      if (cellValue && cellValue !== '\u2014' && cellValue !== '-') {
        var cweStatus = (frameworkRows[j]['Status'] || '').trim();
        mapped.push({
          cwe: frameworkRows[j]['CWE'],
          reference: cellValue,
          status: cweStatus
        });
        if (/OPEN/i.test(cweStatus)) {
          active.push(frameworkRows[j]['CWE']);
        }
      }
    }
    result.frameworkCoverage[framework] = {
      mappedCwes: mapped.length,
      activeCwes: active.length,
      references: mapped
    };
  }

  // Parse aggregate compliance matrix
  var aggRows = parseMarkdownTable(content, /Framework.*CWEs Mapped/i);
  for (var a = 0; a < aggRows.length; a++) {
    var aggRow = aggRows[a];
    var fwName = (aggRow['Framework'] || '').trim();
    var cweMapped = (aggRow['CWEs Mapped'] || '').trim();
    var activeCount = (aggRow['Active CWEs'] || '').trim();
    var coverage = (aggRow['Coverage'] || '').trim();

    if (fwName) {
      result.aggregateMatrix[fwName] = {
        cwesMapped: cweMapped,
        activeCwes: parseInt(activeCount, 10) || 0,
        coverage: coverage
      };
    }
  }

  return result;
}

// ---------------------------------------------------------------------------
// Test suite validation
// ---------------------------------------------------------------------------

function validateAgainstTestSuites(scanData, cweData) {
  var validation = {
    suitesCovered: 0,
    suitesTotal: 0,
    suites: {}
  };

  var allCweIds = cweData.cweInventory.map(function(c) { return c.id; });

  var suiteNames = Object.keys(KNOWN_TEST_SUITES);
  validation.suitesTotal = suiteNames.length;

  for (var i = 0; i < suiteNames.length; i++) {
    var suiteName = suiteNames[i];
    var suite = KNOWN_TEST_SUITES[suiteName];
    var suiteResult = {
      covered: false,
      coverageDetail: null,
      mappedCount: 0,
      totalCount: 0,
      gaps: []
    };

    var aggEntry = cweData.aggregateMatrix[suiteName];

    if (suite.categories) {
      // OWASP Top 10 / LLM Top 10 — check which categories appear
      suiteResult.totalCount = suite.categories.length;
      var fwCoverage = cweData.frameworkCoverage[suiteName];
      if (fwCoverage) {
        var seenCategories = {};
        for (var r = 0; r < fwCoverage.references.length; r++) {
          var ref = fwCoverage.references[r].reference;
          var catMatches = ref.match(/(?:A\d{2}:\d{4}|LLM\d{2})\b/g) || [];
          for (var m = 0; m < catMatches.length; m++) {
            seenCategories[catMatches[m]] = true;
          }
        }
        suiteResult.mappedCount = Object.keys(seenCategories).length;
        for (var c = 0; c < suite.categories.length; c++) {
          var cat = suite.categories[c];
          var catId = (cat.match(/(?:A\d{2}:\d{4}|LLM\d{2})\b/) || [''])[0];
          if (catId && !seenCategories[catId]) {
            suiteResult.gaps.push(cat);
          }
        }
      } else if (aggEntry) {
        var mappedParts = aggEntry.cwesMapped.split('/');
        suiteResult.mappedCount = parseInt(mappedParts[0], 10) || 0;
        suiteResult.totalCount = parseInt(mappedParts[1], 10) || suiteResult.totalCount;
      }
      suiteResult.covered = suiteResult.mappedCount > 0;
      suiteResult.coverageDetail = suiteResult.mappedCount + '/' + suiteResult.totalCount + ' categories assessed';

    } else if (suite.entries) {
      // CWE Top 25 — check which CWE IDs overlap
      suiteResult.totalCount = suite.entries.length;
      var matched = [];
      for (var e = 0; e < suite.entries.length; e++) {
        if (allCweIds.indexOf(suite.entries[e]) !== -1) {
          matched.push(suite.entries[e]);
        } else {
          suiteResult.gaps.push(suite.entries[e]);
        }
      }
      suiteResult.mappedCount = matched.length;
      suiteResult.covered = matched.length > 0;
      suiteResult.coverageDetail = matched.length + '/' + suite.entries.length + ' CWEs assessed';

    } else if (suite.controlFamilies) {
      // NIST — check which control families are referenced
      suiteResult.totalCount = suite.controlFamilies.length;
      var seenFamilies = {};
      var fwRef = cweData.frameworkCoverage[suiteName];
      if (fwRef) {
        for (var n = 0; n < fwRef.references.length; n++) {
          var nistRef = fwRef.references[n].reference;
          var familyMatches = nistRef.match(/\b([A-Z]{2})-/g) || [];
          for (var fm = 0; fm < familyMatches.length; fm++) {
            seenFamilies[familyMatches[fm].replace('-', '')] = true;
          }
        }
      } else if (aggEntry) {
        var coverageParts = (aggEntry.coverage || '').match(/\b([A-Z]{2})\b/g) || [];
        for (var cp = 0; cp < coverageParts.length; cp++) {
          if (suite.controlFamilies.indexOf(coverageParts[cp]) !== -1) {
            seenFamilies[coverageParts[cp]] = true;
          }
        }
      }
      suiteResult.mappedCount = Object.keys(seenFamilies).length;
      for (var nf = 0; nf < suite.controlFamilies.length; nf++) {
        if (!seenFamilies[suite.controlFamilies[nf]]) {
          suiteResult.gaps.push(suite.controlFamilies[nf]);
        }
      }
      suiteResult.covered = suiteResult.mappedCount > 0;
      suiteResult.coverageDetail = suiteResult.mappedCount + '/' + suite.controlFamilies.length + ' control families assessed';

    } else if (suite.articles) {
      // EU AI Act — check article references
      suiteResult.totalCount = suite.articles.length;
      var seenArticles = {};
      var euRef = cweData.frameworkCoverage[suiteName];
      if (euRef) {
        for (var eu = 0; eu < euRef.references.length; eu++) {
          var artRef = euRef.references[eu].reference;
          var artMatches = artRef.match(/Art\.\s*\d+/g) || [];
          for (var am = 0; am < artMatches.length; am++) {
            seenArticles[artMatches[am]] = true;
          }
        }
      } else if (aggEntry) {
        var artFromCoverage = (aggEntry.coverage || '').match(/Art\.\s*\d+/g) || [];
        for (var ac = 0; ac < artFromCoverage.length; ac++) {
          seenArticles[artFromCoverage[ac]] = true;
        }
      }
      suiteResult.mappedCount = Object.keys(seenArticles).length;
      for (var ea = 0; ea < suite.articles.length; ea++) {
        if (!seenArticles[suite.articles[ea]]) {
          suiteResult.gaps.push(suite.articles[ea]);
        }
      }
      suiteResult.covered = suiteResult.mappedCount > 0;
      suiteResult.coverageDetail = suiteResult.mappedCount + '/' + suite.articles.length + ' articles assessed';

    } else if (suite.prefix) {
      // Prefix-based frameworks (MITRE ATT&CK, ATLAS, ISO, SOC 2)
      if (aggEntry) {
        var mappedParts2 = aggEntry.cwesMapped.split('/');
        suiteResult.mappedCount = parseInt(mappedParts2[0], 10) || 0;
        suiteResult.totalCount = parseInt(mappedParts2[1], 10) || 0;
        suiteResult.covered = suiteResult.mappedCount > 0;
        suiteResult.coverageDetail = aggEntry.cwesMapped + ' CWEs mapped, ' + aggEntry.activeCwes + ' active';
      } else {
        var prefRef = cweData.frameworkCoverage[suiteName];
        if (prefRef && prefRef.mappedCwes > 0) {
          suiteResult.mappedCount = prefRef.mappedCwes;
          suiteResult.covered = true;
          suiteResult.coverageDetail = prefRef.mappedCwes + ' CWEs mapped';
        }
      }
    }

    if (suiteResult.covered) validation.suitesCovered++;
    validation.suites[suiteName] = suiteResult;
  }

  return validation;
}

// ---------------------------------------------------------------------------
// Auto-fill fields computation
// ---------------------------------------------------------------------------

function computeAutoFillFields(scanData, cweData, testSuiteValidation) {
  var coverageLevel;
  var ratio = testSuiteValidation.suitesTotal > 0
    ? testSuiteValidation.suitesCovered / testSuiteValidation.suitesTotal
    : 0;
  if (ratio === 0) coverageLevel = 'none';
  else if (ratio <= 0.25) coverageLevel = 'minimal';
  else if (ratio <= 0.5) coverageLevel = 'basic';
  else if (ratio <= 0.75) coverageLevel = 'good';
  else coverageLevel = 'comprehensive';

  var findingSeverity = 'clean';
  if (scanData.findings.critical > 0) findingSeverity = 'critical';
  else if (scanData.findings.high > 0) findingSeverity = 'high';
  else if (scanData.findings.medium > 0) findingSeverity = 'medium';
  else if (scanData.findings.low > 0 || scanData.findings.info > 0) findingSeverity = 'low';

  return {
    testSuiteCoverage: testSuiteValidation.suitesCovered + '/' + testSuiteValidation.suitesTotal + ' suites',
    testSuiteCoverageLevel: coverageLevel,
    highestActiveSeverity: findingSeverity,
    overallAssessment: scanData.overallAssessment || 'UNKNOWN',
    totalFindings: scanData.findings.total,
    resolvedCwes: cweData.resolvedCwes,
    activeCwes: cweData.activeCwes,
    vulnerabilityAssessmentCompleted: true
  };
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

function main() {
  var args = parseArgs(process.argv);
  var repo = args.repo;

  log('Scanning repository: ' + repo);

  if (!isDir(repo)) {
    process.stderr.write('Error: ' + repo + ' is not a directory\n');
    process.exit(1);
  }

  var scanPath = path.join(repo, 'audits', 'sast-dast-scan.md');
  var cwePath = path.join(repo, 'audits', 'cwe-mapping.md');

  var scanContent = readText(scanPath);
  var cweContent = readText(cwePath);

  if (!scanContent && !cweContent) {
    log('No audits/sast-dast-scan.md or audits/cwe-mapping.md found.');
    var emptyOutput = {
      _meta: {
        extractor: 'sast-dast-evidence',
        version: '1.0.0',
        extractedAt: new Date().toISOString(),
        repoPath: repo
      },
      scanReport: { detected: false },
      cweMapping: { detected: false },
      testSuiteValidation: null,
      autoFillFields: {
        testSuiteCoverage: '0/0 suites',
        testSuiteCoverageLevel: 'none',
        vulnerabilityAssessmentCompleted: false
      }
    };
    outputResult(emptyOutput, args.output);
    return;
  }

  // Parse scan report
  var scanData = { detected: false, findings: { critical: 0, high: 0, medium: 0, low: 0, info: 0, total: 0 } };
  if (scanContent) {
    log('Parsing audits/sast-dast-scan.md...');
    scanData = parseSastDastScan(scanContent);
    log('  Findings: ' + scanData.findings.total + ' total (' +
        scanData.findings.critical + ' critical, ' +
        scanData.findings.high + ' high, ' +
        scanData.findings.medium + ' medium)');
    log('  Overall assessment: ' + (scanData.overallAssessment || 'not found'));
  }

  // Parse CWE mapping
  var cweData = { detected: false, uniqueCwes: 0, activeCwes: 0, resolvedCwes: 0, cweInventory: [], frameworkCoverage: {}, aggregateMatrix: {} };
  if (cweContent) {
    log('Parsing audits/cwe-mapping.md...');
    cweData = parseCweMapping(cweContent);
    log('  Unique CWEs: ' + cweData.uniqueCwes + ' (' + cweData.resolvedCwes + ' resolved, ' + cweData.activeCwes + ' active)');
    log('  Frameworks mapped: ' + Object.keys(cweData.aggregateMatrix).length);
  }

  // Validate against known test suites
  log('Validating against known test suites...');
  var testSuiteValidation = validateAgainstTestSuites(scanData, cweData);
  log('  Coverage: ' + testSuiteValidation.suitesCovered + '/' + testSuiteValidation.suitesTotal + ' suites');

  var autoFillFields = computeAutoFillFields(scanData, cweData, testSuiteValidation);

  var output = {
    _meta: {
      extractor: 'sast-dast-evidence',
      version: '1.0.0',
      extractedAt: new Date().toISOString(),
      repoPath: repo,
      files: {
        scanReport: scanContent ? 'audits/sast-dast-scan.md' : null,
        cweMapping: cweContent ? 'audits/cwe-mapping.md' : null
      }
    },
    scanReport: scanData,
    cweMapping: cweData,
    testSuiteValidation: testSuiteValidation,
    autoFillFields: autoFillFields
  };

  outputResult(output, args.output);
  log('Done.');
}

function outputResult(output, outputPath) {
  var json = JSON.stringify(output, null, 2);
  if (outputPath) {
    var outDir = path.dirname(outputPath);
    if (!isDir(outDir)) {
      fs.mkdirSync(outDir, { recursive: true });
    }
    fs.writeFileSync(outputPath, json + '\n', 'utf8');
    log('Evidence written to: ' + outputPath);
  } else {
    process.stdout.write(json + '\n');
  }
}

main();
